def delta_close (δ : M → ℝ) (F G : M → Y) : Prop :=
  ∀ x : M, dist (F x) (G x) < δ x

variable {E : Type v} [NormedAddCommGroup E]

def TopologicalRetraction {X : Type u} [TopologicalSpace X] (M : Set X) :=
  {r : ContinuousMap X M // Function.LeftInverse r ((↑) : M → X)}

namespace TopologicalRetraction

variable {X : Type u} [TopologicalSpace X] {M : Set X}

/-- A topological retraction can be used as its underlying function `X → M`. -/
instance : CoeFun (TopologicalRetraction M) (fun _ ↦ X → M) where
  coe r := r.1

def IsSmoothFamily (I : ModelWithCorners 𝕜 EM HM) (J : ModelWithCorners 𝕜 ES HS)
    (K : ModelWithCorners 𝕜 EN HN) (F : S → N → M) : Prop :=
  ContMDiff (J.prod K) I ∞ (Function.uncurry F)

def SpansTangentBundleOn (A : Set M)
    (X : Fin k → (p : M) → TangentSpace I p) : Prop :=
  ∀ p ∈ A, Submodule.span 𝕜 (Set.range (X · p)) = ⊤

def complex_general_linear_group_identity_tangent_equiv_matrix_apply (n : ℕ) :
    @TangentSpace ℂ _ (Matrix (Fin n) (Fin n) ℂ) _ _ (Matrix (Fin n) (Fin n) ℂ) _
        (𝓘(ℂ, Matrix (Fin n) (Fin n) ℂ)) ((Matrix (Fin n) (Fin n) ℂ)ˣ) inferInstance
        (@Units.instChartedSpace (Matrix (Fin n) (Fin n) ℂ) inferInstance inferInstance)
        (1 : (Matrix (Fin n) (Fin n) ℂ)ˣ) ≃ₗ[ℂ] Matrix (Fin n) (Fin n) ℂ :=
  complex_general_linear_group_identity_tangent_equiv_matrix n
